import{_ as o}from"./plugin-vue_export-helper-c27b6911.js";import{o as t,c as l,e as p}from"./app-5539acff.js";const n={},e=p("<p>GIL：又叫全局解释器锁，每个线程在执行的过程中都需要先获取GIL，保证同一时刻只有一个线程在运行，目的是解决多线程同时竞争解释器资源而出现的线程安全问题。它并不是python语言的特性，仅仅是由于历史的原因在CPython解释器中难以移除，因为python语言运行环境大部分默认在CPython解释器中。</p><p>多线程下每个线程在执行的过程中都需要先获取GIL，保证同一时刻只有一个线程在运行。</p><p>由于GIL的存在，<strong>即使是多线程，事实上同一时刻只能保证一个线程在运行</strong>，既然这样多线程的运行效率不就和单线程一样了吗，那为什么还要使用多线程呢？</p><p>由于以前的电脑基本都是单核CPU，多线程和单线程几乎看不出差别，可是由于计算机的迅速发展，现在的电脑几乎都是多核CPU了，这时差别就出来了：</p><p>即使在多核CPU中，多线程同一时刻也只有一个线程在运行，这样不仅不能利用多核CPU的优势，反而由于每个线程在多个CPU上是交替执行的，导致在不同CPU上切换时造成资源的浪费，反而会更慢。</p><p>即原因是一个进程只存在一把gil锁，当在执行多个线程时，内部会争抢gil锁，这会造成当某一个线程没有抢到锁的时候会让cpu等待，进而不能合理利用多核cpu资源。</p><p>要去除GIL，主要要考虑四个主要技术点。</p><ol><li>引用计数。引用计数在 Python 里是 GCC 的主要方式， C-API 里<code>Py_INCREF</code> 和 <code>Py_DECREF</code> 太好用了，<strong>所有C库都用</strong>。而这些操作都用到了GIL，只要引用计数活着一天，去掉 GIL 就不容易。</li><li>全局和静态变量。这个不用说。</li><li>C扩展的并行和重入。</li><li>原子性。很多 Python 对象都保证原子性，比如基本类型 list、dict 啥的。</li></ol><p>说到在这里要先介绍两个概念：<strong>计算密集型</strong>和<strong>IO密集型</strong></p><p><strong>计算密集型</strong>：要进行大量的数值计算，例如进行上亿的数字计算、计算圆周率、对视频进行高清解码等等。这种计算密集型任务虽然也可以用多任务完成，但是花费的主要时间在任务切换的时间。这类情况使用多进程实现多任务，可以充分利用多核cpu。</p><p><strong>IO密集型</strong>：涉及到网络请求(time.sleep())、磁盘IO的任务都是IO密集型任务，这类任务的特点是CPU消耗很少，任务的大部分时间都在等待IO操作完成（因为IO的速度远远低于CPU和内存的速度）。这类情况使用多线程实现多任务，速度要超过单线程的。</p><blockquote><p>解决GIL问题的方案：</p></blockquote><ul><li>使用其他语言的解释器，如java的解释器jython</li><li>使用其它语言实现多线程，例如C,Java</li><li>使用多进程，是可以利用多核的CPU资源的优势</li></ul>",13),c=[e];function i(s,r){return t(),l("div",null,c)}const I=o(n,[["render",i],["__file","GIL全局解释器锁-418c3602.html.vue"]]);export{I as default};
